@rendermode InteractiveServer

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= currentRating ? "filled" : "")"
              @onclick="() => Rate(star)"
              title="@star star(s)">
            @(star <= currentRating ? "★" : "☆")
        </span>
    }
    <span class="rating-info">(@AverageRating.ToString("0.0") avg, @RatingCount ratings)</span>
</div>

@if (showConfirmation)
{
    <div class="rating-confirmation">Thanks! You rated this @currentRating star(s).</div>
}

@code {
    [Parameter] public double AverageRating { get; set; }
    [Parameter] public int RatingCount { get; set; }
    [Parameter] public int RecipeId { get; set; }

    private int currentRating;
    private bool showConfirmation;

    protected override void OnParametersSet()
    {
        currentRating = (int)Math.Round(AverageRating);
    }

    private void Rate(int stars)
    {
        currentRating = stars;
        showConfirmation = true;
    }
}

@page "/categories/{CategoryName}"
@using RecipeSharing.Models

<PageTitle>@CategoryName Recipes - RecipeSharing</PageTitle>

<h1>@CategoryName Recipes</h1>

<div class="recipe-list">
    @foreach (var recipe in recipes)
    {
        <div class="recipe-card">
            <h3><a href="/recipe/@recipe.Id">@recipe.Title</a></h3>
            <p class="rating-preview">★ @recipe.AverageRating.ToString("0.0") (@recipe.RatingCount ratings)</p>
        </div>
    }
</div>

<p><a href="/">← Back to all categories</a></p>

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;

    private List<Recipe> recipes = new();

    protected override void OnParametersSet()
    {
        recipes = RecipeStore.Recipes
            .Where(r => r.Category.Equals(CategoryName, StringComparison.OrdinalIgnoreCase))
            .ToList();
    }
}

@page "/recipe/{Id:int}"
@using RecipeSharing.Models
@using RecipeSharing.Components.Shared

<PageTitle>@recipe?.Title - RecipeSharing</PageTitle>

@if (recipe is null)
{
    <p>Recipe not found.</p>
}
else
{
    <h1>@recipe.Title</h1>
    <p class="category-badge">@recipe.Category</p>

    <StarRating RecipeId="@recipe.Id"
                AverageRating="@recipe.AverageRating"
                RatingCount="@recipe.RatingCount" />

    <h2>Ingredients</h2>
    <ul>
        @foreach (var ingredient in recipe.Ingredients.Split(',', StringSplitOptions.TrimEntries))
        {
            <li>@ingredient</li>
        }
    </ul>

    <h2>Steps</h2>
    <ol>
        @foreach (var step in recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            var text = step.TrimStart();
            if (text.Length > 2 && text[1] == '.')
                text = text[3..];
            <li>@text</li>
        }
    </ol>

    <p><a href="/categories/@recipe.Category">← Back to @recipe.Category recipes</a></p>
}

@code {
    [Parameter] public int Id { get; set; }

    private Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeStore.Recipes.FirstOrDefault(r => r.Id == Id);
    }
}

@page "/submit"
@rendermode InteractiveServer
@using System.ComponentModel.DataAnnotations
@using RecipeSharing.Models

<PageTitle>Submit a Recipe - RecipeSharing</PageTitle>

<h1>Submit a Recipe</h1>

@if (submitted)
{
    <div class="success-message">
        <h2>Recipe submitted!</h2>
        <p>Your recipe "<strong>@Model.Title</strong>" has been added.</p>
        <p><a href="/recipe/@newRecipeId">View your recipe</a> | <a href="/submit">Submit another</a></p>
    </div>
}
else
{
    <EditForm Model="@Model" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <DataAnnotationsValidator />
        <ValidationSummary />

        <div class="form-group">
            <label for="title">Recipe Title</label>
            <InputText id="title" @bind-Value="Model.Title" class="form-control" />
            <ValidationMessage For="@(() => Model.Title)" />
        </div>

        <div class="form-group">
            <label for="category">Category</label>
            <InputSelect id="category" @bind-Value="Model.Category" class="form-control">
                <option value="">-- Select a category --</option>
                <option value="Italian">Italian</option>
                <option value="Indian">Indian</option>
                <option value="Thai">Thai</option>
                <option value="Mexican">Mexican</option>
                <option value="Other">Other</option>
            </InputSelect>
            <ValidationMessage For="@(() => Model.Category)" />
        </div>

        <div class="form-group">
            <label for="ingredients">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" @bind-Value="Model.Ingredients" class="form-control" rows="5" />
            <ValidationMessage For="@(() => Model.Ingredients)" />
        </div>

        <div class="form-group">
            <label for="steps">Steps (one per line)</label>
            <InputTextArea id="steps" @bind-Value="Model.Steps" class="form-control" rows="6" />
            <ValidationMessage For="@(() => Model.Steps)" />
        </div>

        <button type="submit" class="btn-submit">Submit Recipe</button>
    </EditForm>
}

@code {
    private RecipeFormModel Model { get; set; } = new();
    private bool submitted;
    private int newRecipeId;

    private void HandleSubmit()
    {
        var maxId = RecipeStore.Recipes.Max(r => r.Id);
        var newRecipe = new Recipe
        {
            Id = maxId + 1,
            Title = Model.Title,
            Category = Model.Category,
            Ingredients = Model.Ingredients.Replace("\n", ", "),
            Steps = string.Join("\n", Model.Steps.Split('\n')
                .Select((s, i) => $"{i + 1}. {s.Trim()}")
                .Where(s => s.Length > 3)),
            AverageRating = 0,
            RatingCount = 0
        };
        RecipeStore.Recipes.Add(newRecipe);
        newRecipeId = newRecipe.Id;
        submitted = true;
    }

    public class RecipeFormModel
    {
        [Required(ErrorMessage = "Please enter a recipe title.")]
        [StringLength(100, MinimumLength = 3)]
        public string Title { get; set; } = string.Empty;

        [Required(ErrorMessage = "Please select a category.")]
        public string Category { get; set; } = string.Empty;

        [Required(ErrorMessage = "Please list the ingredients.")]
        public string Ingredients { get; set; } = string.Empty;

        [Required(ErrorMessage = "Please describe the steps.")]
        public string Steps { get; set; } = string.Empty;
    }
}

