<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= currentRating ? "filled" : "")"
              @onclick="() => Rate(star)"
              title="@star star(s)">
            @(star <= currentRating ? "★" : "☆")
        </span>
    }
    <span class="rating-info">(@AverageRating.ToString("0.0") avg, @RatingCount ratings)</span>
</div>

@if (showConfirmation)
{
    <div class="rating-confirmation">Thanks! You rated this @currentRating star(s).</div>
}

